function checkExchangeIntuition() {
            var selected = document.getElementById("scenarioSelect").value;
            var resultBox = document.getElementById("intuitionResultBox");

            var htmlContent = "";
            if(selected === "rise") {
                htmlContent = "<strong>📈 환율 상승 결과 분석:</strong><br>" +
                              "• <strong>달러 가치:</strong> 상대적 강세<br>" +
                              "• <strong>원화 가치:</strong> 달러 대비 상대적 약세<br>" +
                              "• <strong>설명:</strong> 1달러를 사기 위해 더 많은 원화를 지불해야 하므로 원화 기준 해외 결제 비용이 상대적으로 커질 수 있습니다.";
            } else {
                htmlContent = "<strong>📉 환율 하락 결과 분석:</strong><br>" +
                              "• <strong>달러 가치:</strong> 상대적 약세<br>" +
                              "• <strong>원화 가치:</strong> 달러 대비 상대적 강세<br>" +
                              "• <strong>설명:</strong> 1달러를 더 적은 원화로 살 수 있게 되므로 원화 기준 해외 결제 비용이 상대적으로 낮아질 수 있습니다.";
            }

            resultBox.innerHTML = htmlContent;
            resultBox.style.display = "block";
        }

