function diagnoseManagementType() {
            var asset = document.getElementById('assetSizeSelect').value;
            var mental = document.getElementById('mentalSelect').value;
            var resultText = "";

            if (asset === "low" && mental === "cool") {
                resultText = "🎯 <b>[순수 디지털 알고리즘 패키지 정합]</b> 추천! 현재 자산 볼륨에서는 불필요한 고비용 자문 마찰을 줄이고, 합리적인 수수료 구조를 지닌 로보어드바이저의 자동 자산배분 인프라에 운용을 위임하여 시드머니의 복리 보존율을 극대화하는 것이 장기적으로 가성비 면에서 유리합니다.";
            } else if (asset === "high" || mental === "panic") {
                resultText = "🤝 <b>[인간 PB 밀착형 하이브리드 가치 결합]</b> 권장! 하락장에서 심리적 불안으로 인한 뇌동매매 위험이 높거나 복잡한 세무, 상속, 비정형적 솔루션 조율이 가미되어야 하는 패키지 체급입니다. 알고리즘의 정밀 자산배분 인프라를 베이스라인으로 깔되, 금융 시장 위기 상황 시 멘탈을 붙잡아줄 베테랑 프라이빗 뱅커(PB)의 정서적 코칭 안전망을 조화롭게 활용하시는 것이 현명합니다.";
            } else {
                resultText = "📈 <b>[점진적 하이브리드 전환 모델]</b> 추천! 효율적이고 저렴한 로보어드바이저 서비스를 메인 금융 비서로 배치하여 분산투자와 규칙적 리밸런싱의 금융 문해력을 탄탄하게 키워가면서, 향후 자산 규모 성장에 발맞추어 세무·신탁 인프라 설계를 위해 오프라인 전문 PB 네트워크 노드를 유기적으로 엮어가는 스케줄링이 적합합니다

